<script>
import { mapState } from "vuex";
export default {
  name: "footerView",
  computed: {
    ...mapState(["Institucion", "MenuConv", "MenuCur", "url_api"]),
  },
  methods: {
    formatNombreCarrera(nombre) {
      if (!nombre) return '';
      const letras = nombre.split(' ');
      const letrasFormateadas = letras.map(
        letra =>
          letra.charAt(0).toUpperCase() + letra.slice(1).toLowerCase()
      );
      return letrasFormateadas.join(' ');
    },
  },
};
</script>

