      <div class="row">
        <span class="col-xs-6 col-sm-3">
          <!-- <router-link to="/"> -->
            <img :src="url_api + '/InstitucionUpea/' + Institucion.institucion_logo
              " class="img-responsive" alt="img" width="100" height="100" />
          <!-- </router-link> -->
        </span>
        <!-- <div class="col-xs-6 col-sm-3"></div> -->
        <div class="col-xs-6 col-sm-9">
          <div class="contact clearfix">
            <ul class="hidden-xs">
              <li> <span>Email</span>
                <a href="mailto:{{ Institucion.institucion_correo1 }}">{{
                  Institucion.institucion_correo1 }}
                </a>
                <br>
                <a href="mailto:{{ Institucion.institucion_correo2 }}">{{
                  Institucion.institucion_correo2 }}
                </a>
              </li>
              <li>
                <span>Teléfono</span>
                <a :href="'tel:' + Institucion.institucion_telefono1">
                  {{ Institucion.institucion_telefono1 }}
                </a>
                <br>
                <a :href="'tel:' + Institucion.institucion_telefono2">
                  {{ Institucion.institucion_telefono2 }}
                </a>
              </li>
            </ul>
            <a href="http://administracionpaginas.upea.edu.bo/login" target="_blank" class="login">INICIAR SESIÓN<span
                class="icon-more-icon"></span>
            </a>
          </div>
        </div>
      </div>
